import timefrom mistgen.comb_planning_minE import minE_calculation_v3def kd_consistent_score(bbxs_pre,bbxs_curr):    """    Parameters    ----------    bbxs_pre : list        [vid_p,start_x,start_y,start_yaw,l,w,dscore,ss,kds]        ss = [l_ss,w_ss]        start_yaw; in radian     bbxs_curr : list        [vid_p,start_x,start_y,start_yaw,l,w,dscore,ss,kds]        ss = [l_ss,w_ss]        start_yaw; in radian     Returns    -------    ss_bbxs : list        [vid_p,start_x,start_y,start_yaw,l,w,dscore,ss,kds_new]        ss = [l_ss,w_ss]        start_yaw; in radian     """        ss_bbxs = []    for bbx_curr in bbxs_curr:        vid = bbx_curr[0]        for bbx_pre in bbxs_pre:            vid_p = bbx_pre[0]            if vid == vid_p:                minE = minE_calculation_v3(bbx_pre,bbx_curr)                kds = "E" + str(minE)                break             else:                kds = -1        ss_bbx = bbx_curr        ss_bbx[-1] = kds        ss_bbxs.append(ss_bbx)                return ss_bbxsif __name__ == "__main__":    # Test data    bbxs_pre = [        [1, 0.0, 0.0, 0.0, 5.0, 2.2, 0.9,1,1],        [2, -1.0, 1.0, 45.0, 4.0, 1.5, 0.8,1,1],        [3, 2.0, -2.0, -30.0, 6.0, 1.8, 0.7,1,1],        [4, 2.0, -2.0, -30.0, 6.0, 1.4, 0.7,1,1]    ]        bbxs_curr = [        [1, 0.0, 0.0, 0.0, 5.2, 1.8, 0.9,1,1],        [5, -1.0, 1.0, 45.0, 3.8, 1.6, 0.85,1,1],        [3, 2.0, -2.0, -30.0, 5.8, 1.9, 0.75,1,1],        [6, -1.0, 1.0, 45.0, 3.8, 1.6, 0.85,1,],            ]        s_t = time.time()    kd_scores_bbxs = kd_consistent_score(bbxs_pre, bbxs_curr)    e_t = time.time()    print(e_t-s_t)